$files = Get-ChildItem "{{ prj_home_win }}" -Recurse
$NewOwner = New-Object System.Security.Principal.NTAccount("{{ hostname | upper }}","{{ prj_user }}")
Foreach ($file in $files)
{
    $f = $file.FullName
    if ($f.Length -lt 260){
        $acl = (Get-Acl $f)
        If ($acl.Owner -ne $NewOwner) {
            $acl.SetOwner($NewOwner)
            Set-Acl -path $f -aclObject $acl
        }
    }
}

